def find_longest_name(names): 
  longest_name = ""
  for name in names:
    if len(name) > len(longest_name):
      longest_name = name
  return longest_name

print(find_longest_name(["James", "Maria", "Robert"]))

# Output: Robert

def is_prime(n):
  if n <= 1:
    return False
  if n <= 3:  
    return True  
  if n % 2 == 0 or n % 3 == 0: 
    return False  
  i = 5
  while i*i <= n:
    if n % i == 0 or n % (i + 2) == 0: 
      return False
    i = i + 6
  return True

def sum_primes(limit):
    sum = 0
    for number in range(2, limit + 1):
        if all(number % i != 0 for i in range(2, number)):
            sum += number
    return sum

function reverseString(str) {
    let reversedString = '';
    str.split('').forEach(char => reversedString = char + reversedString);
    return reversedString;
}

